import{_ as t,o,c as a,ag as r}from"./chunks/framework.HG0H2VLS.js";const g=JSON.parse('{"title":"CCHeaderGroup — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/cc/patterns/HeaderGroup/HeaderGroup.figma-notes.md","filePath":"public/demos/src/cc/patterns/HeaderGroup/HeaderGroup.figma-notes.md"}'),d={name:"public/demos/src/cc/patterns/HeaderGroup/HeaderGroup.figma-notes.md"};function i(n,e,s,c,p,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="ccheadergroup-—-figma-notes" tabindex="-1">CCHeaderGroup — Figma Notes <a class="header-anchor" href="#ccheadergroup-—-figma-notes" aria-label="Permalink to &quot;CCHeaderGroup — Figma Notes&quot;">​</a></h1><p><strong>Figma file:</strong> <a href="https://www.figma.com/design/ETKqleZdpertwFEo40YB5n/Affino-CC-Hybrid--Design-System?node-id=4105-4238" target="_blank" rel="noreferrer"><code>ETKqleZdpertwFEo40YB5n</code></a> (CC Hybrid Design System) <strong>Tier:</strong> Pattern (composed) <strong>Component set node:</strong> <code>4105:4238</code> (frame name <code>CCHeaderGroup</code>) <strong>Files:</strong> <code>CCHeaderGroup.css</code>, <code>CCHeaderGroup.html</code>, <code>CCHeaderGroup.figma.ts</code>, <code>CCHeaderGroup.figma-notes.md</code></p><hr><h2 id="variant-matrix-verified-from-figma-get-metadata-2026-05-15" tabindex="-1">Variant matrix (verified from Figma <code>get_metadata</code> 2026-05-15) <a class="header-anchor" href="#variant-matrix-verified-from-figma-get-metadata-2026-05-15" aria-label="Permalink to &quot;Variant matrix (verified from Figma `get_metadata` 2026-05-15)&quot;">​</a></h2><p>Single Device axis, 2 variants. <strong>⚠ Figma variant names are swapped vs the rendered widths</strong> — see Authoring Bugs.</p><table tabindex="0"><thead><tr><th>Node ID</th><th>Figma label</th><th>Width</th><th>Treated as</th><th>Composes</th></tr></thead><tbody><tr><td><code>4105:4237</code></td><td>&quot;Device=Mobile&quot;</td><td>1280</td><td><strong>Desktop</strong></td><td>CCTopNavigation Multizone/Desktop + CCHeader Control/Desktop</td></tr><tr><td><code>4105:4236</code></td><td>&quot;Device=Desktop&quot;</td><td>390</td><td><strong>Mobile</strong></td><td>CCTopNavigation Multizone/Mobile + CCHeader Control/Mobile</td></tr></tbody></table><p>Per user decision, <strong>width is the source of truth</strong>. Built as a single responsive HTML structure that collapses via <code>@media (max-width: 767px)</code> — no <code>--mobile</code> modifier class.</p><hr><h2 id="css-class-mapping" tabindex="-1">CSS class mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS class mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma</th><th>CSS</th></tr></thead><tbody><tr><td>Wrapper (<code>CCHeaderGroup</code>)</td><td><code>.cc-header-group</code> (<code>&lt;div&gt;</code>)</td></tr><tr><td><code>CCTopNavigation</code> instance</td><td><code>.cc-top-navigation</code> (CCTopNavigation pattern)</td></tr><tr><td><code>CCHeader</code> instance</td><td><code>.cc-header.cc-header--control</code> (CCHeader pattern)</td></tr></tbody></table><p>CCHeaderGroup itself owns minimal CSS — it&#39;s a thin vertical-stack wrapper around two existing patterns.</p><hr><h2 id="token-mapping" tabindex="-1">Token mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Flex direction</td><td><code>column</code></td></tr><tr><td>Width</td><td><code>100%</code></td></tr><tr><td>Item alignment</td><td><code>stretch</code></td></tr></tbody></table><h3 id="notes-on-composed-height" tabindex="-1">Notes on composed height <a class="header-anchor" href="#notes-on-composed-height" aria-label="Permalink to &quot;Notes on composed height&quot;">​</a></h3><p>Figma shows the CCHeader nested inside CCHeaderGroup Mobile at <code>min-h-[48px]</code>, vs the standalone CCHeader Mobile at <code>min-h-[56px]</code>. <strong>By project decision the composed Header uses the standalone 56px</strong> — the original 48px contextual override was removed (Figma may have been authored inconsistently). The composed children retain their standalone CSS unchanged.</p><hr><h2 id="authoring-bugs-to-flag-to-designer" tabindex="-1">Authoring bugs (to flag to designer) <a class="header-anchor" href="#authoring-bugs-to-flag-to-designer" aria-label="Permalink to &quot;Authoring bugs (to flag to designer)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Where</th><th>Resolution</th></tr></thead><tbody><tr><td>Variant labels swapped</td><td>Component set <code>4105:4238</code>. The 1280px-wide variant is named <code>Device=Mobile</code> (should be Desktop); the 390px-wide variant is named <code>Device=Desktop</code> (should be Mobile).</td><td>Code uses <strong>width as truth</strong>. Designer to rename Figma variants.</td></tr><tr><td>Component composed from only the Control type and Multizone topNav</td><td>Figma only ships one composed variant per device (Multizone+Control). Other compositions (Default topNav + Default header, Default topNav + Sub Text header, etc.) are not represented as compiled variants.</td><td>Documented. Consumers compose CCTopNavigation + CCHeader directly for other combinations.</td></tr></tbody></table><hr><h2 id="token-gaps" tabindex="-1">Token gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token gaps&quot;">​</a></h2><p>None unique to CCHeaderGroup. Inherits gaps from child patterns (see CCTopNavigation figma-notes for portrait-28px and mobile-gap-18px gaps; CCHeader figma-notes for notification-badge-red gap).</p><hr><h2 id="interactions" tabindex="-1">Interactions <a class="header-anchor" href="#interactions" aria-label="Permalink to &quot;Interactions&quot;">​</a></h2><p>CCHeaderGroup owns no interactions — all interactions live in the composed child patterns (CCTopNavigation Zone Selector dropdown, CCHeader kebab dropdown, etc.).</p><hr><h2 id="responsive-behaviour" tabindex="-1">Responsive behaviour <a class="header-anchor" href="#responsive-behaviour" aria-label="Permalink to &quot;Responsive behaviour&quot;">​</a></h2><p>CCHeaderGroup owns no responsive CSS — all responsive behaviour comes from the child patterns (see CCTopNavigation and CCHeader figma-notes).</p><hr><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li><strong>CCTopNavigation</strong> (<code>src/patterns/CCTopNavigation/</code>) — supplies the top dark utility bar.</li><li><strong>CCHeader</strong> (<code>src/patterns/CCHeader/</code>) — supplies the main white header.</li><li>Transitively: Breadcrumb, Button, Dropdown, NotificationBadge, Portraits.</li><li><strong>Lucide</strong> icons via the children.</li></ul><p>Include the children&#39;s CSS + JS files in any page using CCHeaderGroup.</p><hr><h2 id="history" tabindex="-1">History <a class="header-anchor" href="#history" aria-label="Permalink to &quot;History&quot;">​</a></h2><ul><li>2026-05-15: Initial compiled pattern scaffold. Built from Figma component set <code>4105:4238</code> (CC Hybrid Design System). 2 variants reduced to a single responsive HTML structure. Figma authoring bug noted (variant names swapped vs widths) — width treated as truth. A contextual mobile-height override (48px composed vs 56px standalone) was initially added per Figma, then removed on 2026-05-18 — composed Header now inherits the standalone 56px.</li></ul>',35)])])}const m=t(d,[["render",i]]);export{g as __pageData,m as default};
